// DJ OPUS - SECTION 6: SECOND DROP - ACID EUPHORIA
// Everything at once. 303 meets diva meets galactic pads.
setcps(138/60/4)

let masterFilter = slider(3000, 500, 12000, 10, "MASTER Filter")
let acidIntensity = slider(0.5, 0, 0.8, 0.01, "ACID Intensity")
let divaVol = slider(0.4, 0, 0.7, 0.01, "DIVA Voice")
let leadVol = slider(0.35, 0, 0.6, 0.01, "LEAD Melody")

// KICK - full power
let kick = s("bd").bank("RolandTR909")
  .gain(1.15)
  .struct("x x x x")

// CLAP
let clap = s("cp").bank("RolandTR909")
  .gain(0.75)
  .struct("~ x ~ x")
  .room(0.25)

// HATS - driving
let hats = s("hh").bank("RolandTR909")
  .gain(0.45)
  .struct("~ x ~ x ~ x ~ x")
  .cutoff(masterFilter)

// OPEN HAT
let oh = s("oh").bank("RolandTR909")
  .gain(0.35)
  .struct("~ ~ ~ ~ ~ ~ x ~")

// ACID 303 - squelching underneath
let acid = note("<a2 a2 c3 a2 e2 e2 g2 e2>")
  .s("sawtooth")
  .cutoff(sine.range(300, 3000).fast(2))
  .resonance(20)
  .decay(0.15)
  .sustain(0)
  .gain(acidIntensity)
  .struct("x x [x x] x x [~ x] x x")

// DIVA - voice oohs soaring above
let diva = note("<[a3,e4] [e3,b3] [f3,c4] [d3,a3]>".slow(2))
  .s("gm_voice_oohs")
  .gain(divaVol)
  .room(0.85)
  .size(0.9)
  .vowel("<a e i o>".slow(4))

// SYNTH CHOIR - backing
let choir = note("<[a3,c4,e4] [e3,g3,b3] [f3,a3,c4] [d3,f3,a3]>".slow(2))
  .s("gm_synth_choir")
  .gain(divaVol.mul(0.5))
  .room(0.8)

// GALACTIC PAD - still holding it all together
let galactic = note("<[a2,e3,a3] [e2,b2,e3] [f2,c3,f3] [d2,a2,d3]>".slow(2))
  .s("gm_pad_sweep")
  .gain(0.25)
  .cutoff(perlin.range(400, 2500).slow(16))
  .room(0.9)
  .size(0.95)

// LEAD - emotional supersaw melody
let lead = note("a4 ~ c5 ~ e5 ~ a5 e5 ~ c5 a4 ~ e4 ~ a4 ~")
  .s("sawtooth")
  .superimpose(x => x.add(0.08))
  .superimpose(x => x.add(-0.08))
  .cutoff(masterFilter)
  .resonance(4)
  .decay(0.4)
  .sustain(0.15)
  .gain(leadVol)
  .delay(0.4)
  .delaytime(3/8)
  .delayfeedback(0.35)
  .room(0.6)
  .jux(rev)

// CRASH
let crash = s("oh").bank("RolandTR909")
  .speed(0.4)
  .gain(0.45)
  .room(0.9)
  .struct("x ~ ~ ~ ~ ~ ~ ~")
  .slow(4)

stack(kick, clap, hats, oh, acid, diva, choir, galactic, lead, crash)
